import { serve } from "https://deno.land/std@0.168.0/http/server.ts";

// Template Excel base64
const TEMPLATE_B64 = "";

serve(async (req) => {
  // CORS
  if (req.method === "OPTIONS") {
    return new Response("ok", {
      headers: {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
      },
    });
  }

  try {
    const { estab, extintores, encargado, fecha_insp, fecha_inf, num_inf } = await req.json();

    // Decode template
    const tplBytes = Uint8Array.from(atob(TEMPLATE_B64), c => c.charCodeAt(0));

    // Use ExcelJS via CDN (not available in Deno easily)
    // Instead: use xlsx from esm.sh
    const XLSX = await import("https://esm.sh/xlsx@0.18.5");
    
    const wb = XLSX.read(tplBytes, { type: "array", cellStyles: true });
    const ws = wb.Sheets["Lista de chequeo extintores"];

    function setVal(addr: string, val: string) {
      if (!ws[addr]) ws[addr] = { t: "s" };
      ws[addr].v = val;
      ws[addr].t = "s";
      ws[addr].w = val;
    }

    // Fill header
    setVal("F8", estab || "");
    setVal("F9", "Dra. Claudia Véjar Pino");
    setVal("F10", encargado || "");
    setVal("F11", fecha_insp || "");
    setVal("F12", fecha_inf || "");
    setVal("F13", num_inf || "");
    
    // Fill firma
    setVal("K43", encargado || "");

    // Fill data rows starting at row 18
    const startRow = 18;
    (extintores || []).forEach((ext: any, i: number) => {
      const r = startRow + i;
      setVal("B" + r, String(ext.numero || ""));
      setVal("C" + r, ext.ubicacion || "");
      setVal("D" + r, ext.tipo || "");
      setVal("E" + r, ext.capacidad || "");
      setVal("G" + r, ext.fecha_carga || "");
      setVal("H" + r, ext.fecha_vence || "");
      setVal("I" + r, ext.fecha_ph || "");
    });

    // Generate output
    const output = XLSX.write(wb, { type: "array", bookType: "xlsx", cellStyles: true });
    const outBytes = new Uint8Array(output);

    return new Response(outBytes, {
      headers: {
        "Access-Control-Allow-Origin": "*",
        "Content-Type": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        "Content-Disposition": `attachment; filename="Lista_extintores.xlsx"`,
      },
    });
  } catch (e) {
    return new Response(JSON.stringify({ error: e.message }), {
      status: 500,
      headers: { 
        "Access-Control-Allow-Origin": "*",
        "Content-Type": "application/json" 
      },
    });
  }
});
